// Animated GIF export -------------------------------------------------------
// The game is drawn on one canvas. Replaying the solved path and cropping at
// the top edge of the controls gives the export exactly the useful play area:
// HUD/stopwatch, graph, ship, trace, and the submitted function.
const GIF_CAPTURE_HEIGHT=217;

function graphQuestGifPalette(){
    const palette=new Uint8Array(256*3);
    for(let i=0;i<256;i++){
        palette[i*3]=Math.round(((i>>5)&7)*255/7);
        palette[i*3+1]=Math.round(((i>>2)&7)*255/7);
        palette[i*3+2]=(i&3)*85;
    }
    return palette;
}

function graphQuestGifPixels(imageData){
    const src=imageData.data,out=new Uint8Array(imageData.width*imageData.height);
    for(let s=0,d=0;d<out.length;s+=4,d++)out[d]=(src[s]>>5)<<5|(src[s+1]>>5)<<2|src[s+2]>>6;
    return out;
}

function graphQuestGifLzw(pixels){
    const clear=256,eoi=257,bytes=[];
    let block=0,bits=0,codeSize=9,next=258,dict=new Map;
    const write=code=>{
        block|=code<<bits;bits+=codeSize;
        while(bits>=8){bytes.push(block&255);block>>>=8;bits-=8}
    };
    const reset=()=>{dict=new Map;codeSize=9;next=258};
    write(clear);
    let prefix=pixels[0]??0;
    for(let i=1;i<pixels.length;i++){
        const suffix=pixels[i],key=prefix*256+suffix,found=dict.get(key);
        if(found!==undefined){prefix=found;continue}
        write(prefix);
        if(next<4096){
            dict.set(key,next++);
            // The decoder creates each dictionary entry one emitted code later
            // than the encoder, so change widths on the following entry.
            if(next>(1<<codeSize)&&codeSize<12)codeSize++;
        }else{
            write(clear);reset();
        }
        prefix=suffix;
    }
    write(prefix);write(eoi);
    if(bits>0)bytes.push(block&255);
    return bytes;
}

function graphQuestEncodeGif(frames,width,height,delay=10){
    const out=[],push=(...values)=>out.push(...values),word=value=>push(value&255,value>>8&255),ascii=value=>{for(const c of value)push(c.charCodeAt(0))};
    ascii("GIF89a");word(width);word(height);push(0xf7,0,0);push(...graphQuestGifPalette());
    // Loop forever.
    push(0x21,0xff,0x0b);ascii("NETSCAPE2.0");push(3,1,0,0,0);
    for(const frame of frames){
        push(0x21,0xf9,4,0);word(delay);push(0,0);
        push(0x2c);word(0);word(0);word(width);word(height);push(0,8);
        const data=graphQuestGifLzw(frame);
        for(let i=0;i<data.length;i+=255){const size=Math.min(255,data.length-i);push(size,...data.slice(i,i+size))}
        push(0);
    }
    push(0x3b);
    return new Blob([new Uint8Array(out)],{type:"image/gif"});
}

